import http from "../http-common";
import authHeader from "./auth-header";

const getPublicContent = () => {
  return http.get("/all");
};

const getUserBoard = () => {
  return http.get("/user", { headers: authHeader() });
};

const getModeratorBoard = () => {
  return http.get("/mod", { headers: authHeader() });
};

const getAdminBoard = () => {
  return http.get("/admin", { headers: authHeader() });
};

const retrieveReviewers = () => {
  return http.get("/reviewer", { headers: authHeader() });
};

const retrieveAllUsers = (params = {}) => {
  const query = new URLSearchParams();
  if (params.page) query.set("page", params.page);
  if (params.size !== undefined && params.size !== null)
    query.set("size", params.size);
  if (params.name) query.set("name", params.name);
  return http.get(`/userList?${query.toString()}`, { headers: authHeader() });
};

const findByName = (name) => {
  return http.get(`/users?name=${name}`, { headers: authHeader() });
};

const update = (id, data) => {
  return http.put(`/users/${id}`, data, { headers: authHeader() });
};

const deactivate = (id) => {
  return http.put(`/users/${id}/deactivate`, {}, { headers: authHeader() });
};

const activate = (id) => {
  return http.put(`/users/${id}/activate`, {}, { headers: authHeader() });
};

const get = (id) => {
  return http.get(`/users/${id}`, { headers: authHeader() });
};

const updatePreferences = (data) => {
  return http.put("/users/preferences", data, { headers: authHeader() });
};

const UserService = {
  get,
  getPublicContent,
  getUserBoard,
  getModeratorBoard,
  getAdminBoard,
  retrieveReviewers,
  retrieveAllUsers,
  findByName,
  update,
  deactivate,
  activate,
  updatePreferences,
};

export default UserService;
